  ('locality-6f0ba476-moex-00388', 'locality-6f0ba476', 'locality-6f0ba476-moex-111-3e700a6a', 'sub-locality-6f0ba476-05', NULL, 'single_choice', '依所得稅法規定，信託關係人之間移轉信託財產不課徵所得稅之情形，下列何者錯誤？', '["因信託行為成立，受託人與受益人間", "信託關係存續中受託人變更時，原受託人與新受託人間", "信託關係存續中，受託人依信託本旨交付信託財產，受託人與受益人間", "因信託關係消滅，委託人與受託人間或受託人與受益人間"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:04+00:00", "source_pdf_sha1": "cb701418f2fb", "answer_pdf_sha1": "47f8da9ec5c3", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "314", "s": "1412", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00389', 'locality-6f0ba476', 'locality-6f0ba476-moex-111-3e700a6a', 'sub-locality-6f0ba476-05', NULL, 'single_choice', '消費者甲消費x與y兩種商品，這兩種商品對甲而言均為正常財且非完全互補，x與y的邊際社 會成本均固定不變。現有兩種稅制，一是僅對x財貨課貨物稅，二是課徵定額稅。下列敘述何者 錯誤？', '["稅收相同下，貨物稅比定額稅產生更多的超額負擔", "稅收相同下，貨物稅比定額稅減少更多的x財貨", "稅收相同下，貨物稅比定額稅減少更多的y財貨", "若x財貨減少的數量相同，貨物稅的稅收少於定額稅之稅收"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:04+00:00", "source_pdf_sha1": "cb701418f2fb", "answer_pdf_sha1": "47f8da9ec5c3", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "314", "s": "1412", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00390', 'locality-6f0ba476', 'locality-6f0ba476-moex-111-3e700a6a', 'sub-locality-6f0ba476-05', NULL, 'single_choice', '假設政府對邊際生產成本為固定的獨占商品課稅，下列敘述何者正確？', '["若為直線性需求，消費者的租稅負擔大於課徵的租稅", "若為直線性需求，消費者的租稅負擔等於課徵的租稅", "若為固定彈性需求，消費者的租稅負擔等於課徵的租稅", "若為固定彈性需求，消費者的租稅負擔大於課徵的租稅"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:04+00:00", "source_pdf_sha1": "cb701418f2fb", "answer_pdf_sha1": "47f8da9ec5c3", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "314", "s": "1412", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00391', 'locality-6f0ba476', 'locality-6f0ba476-moex-111-3e700a6a', 'sub-locality-6f0ba476-05', NULL, 'single_choice', '在肉品市場上，需求曲線呈負斜率，長期供給曲線為水平線。其他條件不變時，政府實施定額補 貼肉品市場，則：', '["肉農戶獲得補貼的利益", "肉農戶收到補貼後較低的市價", "消費者享受補貼的利益", "消費者支付補貼前均衡市價"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:04+00:00", "source_pdf_sha1": "cb701418f2fb", "answer_pdf_sha1": "47f8da9ec5c3", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "314", "s": "1412", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00392', 'locality-6f0ba476', 'locality-6f0ba476-moex-111-3e700a6a', 'sub-locality-6f0ba476-05', NULL, 'single_choice', '瓶裝飲料與手搖飲互為替代品，假設此兩財貨的邊際成本皆為固定，需求曲線則為負斜率的直線。 若政府原本只對瓶裝飲料課稅，現若開始對手搖飲課稅，根據次佳理論，對瓶裝飲料與手搖飲課 稅的超額負擔相較於只對瓶裝飲料課稅產生的超額負擔，下列敘述何者正確？', '["一定較大", "一定較小", "可能較小", "一定相同"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:04+00:00", "source_pdf_sha1": "cb701418f2fb", "answer_pdf_sha1": "47f8da9ec5c3", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "314", "s": "1412", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00393', 'locality-6f0ba476', 'locality-6f0ba476-moex-111-3e700a6a', 'sub-locality-6f0ba476-05', NULL, 'single_choice', '若消費者的效用取決於X、Y兩財貨的消費與休閒L的數量，且X、Y兩財貨與休閒均為中立財。 在既定的時間稟賦下，政府對X、Y兩財貨與休閒L分別課徵稅率為t 、t 、t 的從價稅，下列 X Y L 何種稅制對該消費者所產生的超額負擔最大？', '["t =10%，t =10%，t =10%", "t =20%，t =20%，t =20% X Y L X Y L", "t =5%，t =10%，t =10%", "t =10%，t =20%，t =20% X Y L X Y L"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:04+00:00", "source_pdf_sha1": "cb701418f2fb", "answer_pdf_sha1": "47f8da9ec5c3", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "314", "s": "1412", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00394', 'locality-6f0ba476', 'locality-6f0ba476-moex-111-3e700a6a', 'sub-locality-6f0ba476-05', NULL, 'single_choice', '關於「雙重紅利假說（double-dividendhypothesis）」之敘述，下列何者正確？', '["課徵庇古稅（Pigouviantax）可以改善環境污染與所得分配", "課徵庇古稅，並利用此稅收來降低消費稅率", "課徵庇古稅，除改善環境污染外，並利用此稅收來降低與所得稅有關的無效率稅率", "課徵庇古稅，並利用此稅收來降低遺產稅率"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:04+00:00", "source_pdf_sha1": "cb701418f2fb", "answer_pdf_sha1": "47f8da9ec5c3", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "314", "s": "1412", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL)
